reg [7:0] Memory[0:15];
reg [3:0] addr_reg;
always @(posedge clk) begin
  if (en) addr_reg <= addr;
end
assign data = Memory[addr_reg];

reg [7:0] Memory[0:15];
reg en_reg;
reg [3:0] addr_reg;
always @(posedge clk) begin
  en_reg <= en;
  addr_reg <= addr;
end
assign data = en_reg ? Memory[addr_reg] : 8'b0;
